# Define the sales data according to the description given in the graph
sales_data = dict([
    (1994, 10),
    (1995, 12),
    (1996, 11),
    (1997, 13),
    (1998, 15),
    (1999, 14),
    (2000, 16),
    (2001, 18)
])

# Calculate the differences between sales data of consecutive years
sales_diff = {}
for year in sales_data.keys():
    oldest_date = min(sales_data.keys(), key=lambda k: abs(k - year))
    diff = sales_data[year] - sales_data[oldest_date]
    sales_diff[year] = diff

# Find the year that has the greatest increase following 1994
year_after_1994 = max(sales_diff.keys() - {'1994'}, key=lambda k: sales_diff[k])

print(year_after_1994)
